class Solution:
    def smallestMissingValueSubtree(self, parents, nums):
        n = len(parents)
        children = [[] for _ in range(n)]
        for i in range(1, n):
            children[parents[i]].append(i)
        def subtree_values(root):
            vals = set()
            stack = [root]
            while stack:
                cur = stack.pop()
                vals.add(nums[cur])
                stack.extend(children[cur])
            return vals
        ans = [1] * n
        for node in range(n):
            vals = subtree_values(node)
            mex = 1
            while mex in vals:
                mex += 1
            ans[node] = mex
        return ans

