class Solution:
    def smallestMissingValueSubtree(self, parents, nums):
        n = len(parents)
        ans = [1] * n
        target = -1
        for i, v in enumerate(nums):
            if v == 1:
                target = i
                break
        if target == -1:
            return ans
        children = [[] for _ in range(n)]
        for i in range(1, n):
            children[parents[i]].append(i)
        visited = set()
        mex = 1
        node = target
        prev = -1
        while node != -1:
            stack = [node]
            while stack:
                cur = stack.pop()
                if cur == prev:
                    continue
                visited.add(nums[cur])
                for ch in children[cur]:
                    stack.append(ch)
            while mex in visited:
                mex += 1
            ans[node] = mex
            prev = node
            node = parents[node]
        return ans

