var smallestMissingValueSubtree = function(parents, nums) {
    const n = parents.length;
    const ans = new Array(n).fill(1);
    let target = -1;
    for (let i = 0; i < n; i++) {
        if (nums[i] === 1) { target = i; break; }
    }
    if (target === -1) return ans;
    const children = Array.from({length: n}, () => []);
    for (let i = 1; i < n; i++) children[parents[i]].push(i);
    const visited = new Set();
    let mex = 1;
    let node = target;
    let prev = -1;
    while (node !== -1) {
        const stack = [node];
        while (stack.length) {
            const cur = stack.pop();
            if (cur === prev) continue;
            visited.add(nums[cur]);
            for (const ch of children[cur]) stack.push(ch);
        }
        while (visited.has(mex)) mex++;
        ans[node] = mex;
        prev = node;
        node = parents[node];
    }
    return ans;
};
